module priority_encoder_4to2(
    input [3:0] in,
    output reg [1:0] invalid_out,
    output valid);

    assign valid = |in;

    always @(*) begin
        casex (in)
            4'b1xxx: invalid_out = 2'b11;
            4'b01xx: invalid_out = 2'b10;
            4'b001x: invalid_out = 2'b01;
            4'b0001: invalid_out = 2'b00;
            default: invalid_out = 2'b00;
        endcase
    end
endmodule
